import{_ as t,o,c as a,ag as i}from"./chunks/framework.BYYsWsaA.js";const g=JSON.parse('{"title":"Writing a Note","description":"","frontmatter":{},"headers":[],"relativePath":"notes/writing-a-note.md","filePath":"notes/writing-a-note.md"}'),r={name:"notes/writing-a-note.md"};function s(n,e,d,l,h,c){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="writing-a-note" tabindex="-1">Writing a Note <a class="header-anchor" href="#writing-a-note" aria-label="Permalink to &quot;Writing a Note&quot;">​</a></h1><p>Notes are lightweight <strong>Markdown</strong> documents in Wafflebase. Unlike the word-processor Docs editor, a note is written as Markdown <em>source</em> on one side with a live rendered <em>preview</em> on the other — a fast way to jot down meeting notes, drafts, and technical documentation, with the same real-time collaboration as every other document type.</p><h2 id="create-a-note" tabindex="-1">Create a Note <a class="header-anchor" href="#create-a-note" aria-label="Permalink to &quot;Create a Note&quot;">​</a></h2><ol><li>Open your workspace</li><li>Click the <strong>New</strong> dropdown button</li><li>Select <strong>New Note</strong></li></ol><p>A blank note opens with the editor and preview side by side.</p><h2 id="the-editor" tabindex="-1">The Editor <a class="header-anchor" href="#the-editor" aria-label="Permalink to &quot;The Editor&quot;">​</a></h2><p>The left pane is a Markdown source editor. Type standard Markdown and watch the right pane render it live as you go.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Project Kickoff</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Agenda</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Introductions</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Timeline review</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;"> **Next steps**</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">See the [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">design doc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">https://example.com</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) for details.</span></span></code></pre></div><h3 id="choose-your-view" tabindex="-1">Choose Your View <a class="header-anchor" href="#choose-your-view" aria-label="Permalink to &quot;Choose Your View&quot;">​</a></h3><p>Use the <strong>view</strong> dropdown at the right of the toolbar to switch between three modes:</p><ul><li><strong>Split</strong> — source editor and preview side by side (the default)</li><li><strong>Editor</strong> — Markdown source only, full width</li><li><strong>Preview</strong> — rendered output only</li></ul><p>Your choice is remembered per browser, so the note opens the same way next time.</p><h2 id="formatting-toolbar" tabindex="-1">Formatting Toolbar <a class="header-anchor" href="#formatting-toolbar" aria-label="Permalink to &quot;Formatting Toolbar&quot;">​</a></h2><p>When the editor is visible, a toolbar gives you one-click Markdown for the most common styles. Select some text first, then click a button to wrap it:</p><table tabindex="0"><thead><tr><th>Button</th><th>Inserts</th><th>Result</th></tr></thead><tbody><tr><td><strong>B</strong></td><td><code>**text**</code></td><td><strong>Bold</strong></td></tr><tr><td><em>I</em></td><td><code>*text*</code></td><td><em>Italic</em></td></tr><tr><td><s>S</s></td><td><code>~~text~~</code></td><td><s>Strikethrough</s></td></tr><tr><td>Link</td><td><code>[text](url)</code></td><td>A hyperlink</td></tr><tr><td>Table</td><td>A GFM table skeleton</td><td>A Markdown table</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The <strong>Insert table</strong> button shows a small grid — hover to choose the number of rows and columns, then click to drop in a ready-to-fill table.</p></div><h2 id="what-the-preview-renders" tabindex="-1">What the Preview Renders <a class="header-anchor" href="#what-the-preview-renders" aria-label="Permalink to &quot;What the Preview Renders&quot;">​</a></h2><p>The preview supports <strong>GitHub-Flavored Markdown</strong> plus a few extras:</p><ul><li><strong>Tables</strong> — standard <code>| col | col |</code> GFM tables</li><li><strong>Task lists</strong> — <code>- [ ]</code> and <code>- [x]</code> render as checkboxes</li><li><strong>Code blocks</strong> — fenced \`\`\` blocks get syntax highlighting and a <strong>Copy</strong> button in the corner</li><li><strong>Math</strong> — inline <code>$…$</code> and block <code>$$…$$</code> render with KaTeX</li><li><strong>Links, headings, lists, blockquotes, images</strong> — as you&#39;d expect</li></ul><p>For safety, the preview does <strong>not</strong> render raw HTML embedded in your Markdown — only Markdown syntax is rendered.</p><h2 id="keyboard-mode" tabindex="-1">Keyboard Mode <a class="header-anchor" href="#keyboard-mode" aria-label="Permalink to &quot;Keyboard Mode&quot;">​</a></h2><p>Prefer modal editing? Open the <strong>keyboard</strong> dropdown in the toolbar and switch from <strong>Default</strong> to <strong>Vim</strong>. Vim keybindings then apply inside the source editor. Like the view mode, this is remembered per browser.</p><p>Standard editing shortcuts work in Default mode:</p><table tabindex="0"><thead><tr><th>Action</th><th>Shortcut</th></tr></thead><tbody><tr><td>Undo</td><td>⌘+Z / Ctrl+Z</td></tr><tr><td>Redo</td><td>⌘+Shift+Z / Ctrl+Shift+Z</td></tr><tr><td>Select all</td><td>⌘+A / Ctrl+A</td></tr><tr><td>Copy / Cut / Paste</td><td>⌘+C·X·V / Ctrl+C·X·V</td></tr></tbody></table><h2 id="collaborate-in-real-time" tabindex="-1">Collaborate in Real Time <a class="header-anchor" href="#collaborate-in-real-time" aria-label="Permalink to &quot;Collaborate in Real Time&quot;">​</a></h2><p>Notes sync live through Wafflebase&#39;s CRDT engine, just like sheets, docs, and slides. When a teammate opens the same note:</p><ul><li>Their edits appear instantly as they type</li><li>You see their <strong>cursor and text selection</strong> in their own color</li><li>No saving, refreshing, or merge step is ever needed</li></ul><p>Share a note the same way as any document — click <strong>Share</strong> in the header to create a view or edit link. See <a href="/docs/guide/collaboration.html">Collaboration &amp; Sharing</a> for the full sharing flow.</p><h2 id="rename-a-note" tabindex="-1">Rename a Note <a class="header-anchor" href="#rename-a-note" aria-label="Permalink to &quot;Rename a Note&quot;">​</a></h2><p>Click the note&#39;s title in the header to rename it. The new title appears in your workspace document list immediately.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Notes are ideal for content you&#39;d otherwise keep in a <code>README</code> or a Markdown scratchpad — release notes, runbooks, and specs — kept in sync with your team without leaving Wafflebase.</p></div>`,31)])])}const k=t(r,[["render",s]]);export{g as __pageData,k as default};
